function TitleBanner({ lines, color, tilt = "left" }) {
  const base = tilt === "right" ? 2 : -2;
  return (
    <div className="pg-title-banner">
      {lines.map((line, i) => (
        <span
          key={line}
          className="pg-banner-strip"
          style={{
            background: color,
            transform: `rotate(${i === 0 ? base : -base}deg)`,
            zIndex: lines.length - i,
          }}
        >
          {line}
        </span>
      ))}
    </div>
  );
}

