/* Motion graphics tile — shows a real YouTube thumbnail + opens it in an
   in-page lightbox once a videoId is supplied; falls back to a labeled
   placeholder otherwise. Supports both landscape edits and vertical Shorts. */
function ReelTile({ label, videoId, aspect = "landscape", customThumb, provider = "youtube", onOpen }) {
  const [vimeoThumb, setVimeoThumb] = useState(null);

  useEffect(() => {
    if (customThumb || !videoId || provider !== "vimeo") return;
    let cancelled = false;
    fetch(`https://vimeo.com/api/oembed.json?url=https://vimeo.com/${videoId}`)
      .then((res) => (res.ok ? res.json() : null))
      .then((data) => {
        if (!cancelled && data && data.thumbnail_url) setVimeoThumb(data.thumbnail_url);
      })
      .catch(() => {
        /* silently fall back to placeholder if the fetch fails */
      });
    return () => {
      cancelled = true;
    };
  }, [videoId, provider, customThumb]);

  const thumbSrc =
    customThumb ||
    (videoId && provider === "youtube" ? `https://i.ytimg.com/vi/${videoId}/hqdefault.jpg` : null) ||
    (videoId && provider === "vimeo" ? vimeoThumb : null);

  if (!thumbSrc) {
    return (
      <div
        className={`pg-reel pg-placeholder pg-reel-${aspect}`}
        role="img"
        aria-label={`Placeholder for motion graphics piece: ${label}`}
      >
        <span className="pg-reel-play">&#9658;</span>
        <span>{label}</span>
      </div>
    );
  }

  // Has a thumbnail (custom frame and/or auto-fetched thumb) but no video
  // linked yet — show the preview, but it's not clickable until videoId is set.
  if (!videoId) {
    return (
      <div className={`pg-reel pg-reel-${aspect}`} aria-label={`Preview of ${label} — video link coming soon`}>
        <img src={thumbSrc} alt="" aria-hidden="true" className="pg-reel-thumb" />
        <span className="pg-reel-play pg-reel-play-overlay">&#9658;</span>
      </div>
    );
  }

  return (
    <button
      type="button"
      className={`pg-reel pg-reel-${aspect}`}
      onClick={() => onOpen({ videoId, aspect, label, provider })}
      aria-label={`Play ${label}`}
    >
      <img src={thumbSrc} alt="" aria-hidden="true" className="pg-reel-thumb" />
      <span className="pg-reel-play pg-reel-play-overlay">&#9658;</span>
    </button>
  );
}

