/* Full-screen in-page video popout. Closes on backdrop click, X, or Escape. */
function VideoLightbox({ video, onClose }) {
  useEffect(() => {
    if (!video) return;
    const onKey = (e) => {
      if (e.key === "Escape") onClose();
    };
    document.addEventListener("keydown", onKey);
    document.body.style.overflow = "hidden";
    return () => {
      document.removeEventListener("keydown", onKey);
      document.body.style.overflow = "";
    };
  }, [video, onClose]);

  if (!video) return null;

  const isVimeo = video.provider === "vimeo";
  const embedSrc = isVimeo
    ? `https://player.vimeo.com/video/${video.videoId}?autoplay=1`
    : `https://www.youtube.com/embed/${video.videoId}?autoplay=1&rel=0`;
  const watchUrl = isVimeo
    ? `https://vimeo.com/${video.videoId}`
    : `https://youtu.be/${video.videoId}`;
  const watchLabel = isVimeo ? "Watch on Vimeo" : "Watch on YouTube";

  return (
    <div className="pg-lightbox-backdrop" onClick={onClose}>
      <div
        className={`pg-lightbox-frame pg-lightbox-${video.aspect}`}
        onClick={(e) => e.stopPropagation()}
      >
        <button
          type="button"
          className="pg-lightbox-close"
          onClick={onClose}
          aria-label="Close video"
        >
          &times;
        </button>
        <iframe
          src={embedSrc}
          title={video.label}
          allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
          allowFullScreen
          frameBorder="0"
        />
        <a
          className="pg-lightbox-fallback"
          href={watchUrl}
          target="_blank"
          rel="noopener noreferrer"
        >
          Video not loading? {watchLabel} &rarr;
        </a>
      </div>
    </div>
  );
}

function ReelCarousel({ onOpen }) {
  // Duplicate the list so the track can loop seamlessly at -50%.
  const track = [...reelItems, ...reelItems];
  return (
    <div className="pg-carousel">
      <div className="pg-carousel-track">
        {track.map((item, i) => (
          <ReelTile key={`${item.label}-${i}`} {...item} onOpen={onOpen} />
        ))}
      </div>
    </div>
  );
}

